from dataclasses import dataclass, field
from enum import Enum
from typing import Optional
from datetime import datetime
import uuid


class TransactionType(Enum):
    DEPOSIT = "deposit"
    WITHDRAWAL = "withdrawal"
    TRANSFER = "transfer"


class TransactionStatus(Enum):
    PENDING = "pending"
    COMPLETED = "completed"
    FAILED = "failed"
    REVERSED = "reversed"


class InsufficientFundsError(Exception):
    pass


class AccountNotFoundError(Exception):
    pass


class InvalidTransactionError(Exception):
    pass


@dataclass
class Transaction:
    transaction_id: str
    transaction_type: TransactionType
    amount: float
    source_account_id: Optional[str]
    destination_account_id: Optional[str]
    timestamp: datetime
    status: TransactionStatus = TransactionStatus.PENDING
    description: str = ""

    def __post_init__(self):
        if self.amount <= 0:
            raise InvalidTransactionError("Transaction amount must be positive.")


@dataclass
class Account:
    account_id: str
    owner_name: str
    balance: float = 0.0
    transaction_history: list = field(default_factory=list)
    is_active: bool = True

    def __post_init__(self):
        if self.balance < 0:
            raise ValueError("Initial balance cannot be negative.")


class TransactionProcessor:
    def __init__(self):
        self.accounts: dict[str, Account] = {}
        self.transactions: dict[str, Transaction] = {}

    def create_account(self, owner_name: str, initial_balance: float = 0.0) -> Account:
        account_id = str(uuid.uuid4())[:8]
        account = Account(
            account_id=account_id,
            owner_name=owner_name,
            balance=initial_balance
        )
        self.accounts[account_id] = account
        return account

    def get_account(self, account_id: str) -> Account:
        if account_id not in self.accounts:
            raise AccountNotFoundError(f"Account {account_id} not found.")
        return self.accounts[account_id]

    def _validate_account_active(self, account_id: str) -> Account:
        account = self.get_account(account_id)
        if not account.is_active:
            raise InvalidTransactionError(f"Account {account_id} is inactive.")
        return account

    def process_transaction(self, transaction: Transaction) -> Transaction:
        """Main method to process a financial transaction."""
        try:
            if transaction.transaction_type == TransactionType.DEPOSIT:
                self._process_deposit(transaction)
            elif transaction.transaction_type == TransactionType.WITHDRAWAL:
                self._process_withdrawal(transaction)
            elif transaction.transaction_type == TransactionType.TRANSFER:
                self._process_transfer(transaction)
            else:
                raise InvalidTransactionError(f"Unknown transaction type: {transaction.transaction_type}")

            transaction.status = TransactionStatus.COMPLETED

        except (InsufficientFundsError, AccountNotFoundError, InvalidTransactionError) as e:
            transaction.status = TransactionStatus.FAILED
            transaction.description += f" | FAILED: {str(e)}"

        self.transactions[transaction.transaction_id] = transaction
        return transaction

    def _process_deposit(self, transaction: Transaction):
        if transaction.destination_account_id is None:
            raise InvalidTransactionError("Deposit must have a destination account.")

        account = self._validate_account_active(transaction.destination_account_id)
        account.balance += transaction.amount
        account.balance = round(account.balance, 2)
        account.transaction_history.append(transaction.transaction_id)

    def _process_withdrawal(self, transaction: Transaction):
        if transaction.source_account_id is None:
            raise InvalidTransactionError("Withdrawal must have a source account.")

        account = self._validate_account_active(transaction.source_account_id)

        if account.balance < transaction.amount:
            raise InsufficientFundsError(
                f"Insufficient funds in account {account.account_id}. "
                f"Balance: {account.balance}, Requested: {transaction.amount}"
            )

        account.balance -= transaction.amount
        account.balance = round(account.balance, 2)
        account.transaction_history.append(transaction.transaction_id)

    def _process_transfer(self, transaction: Transaction):
        if transaction.source_account_id is None or transaction.destination_account_id is None:
            raise InvalidTransactionError("Transfer must have both source and destination accounts.")

        if transaction.source_account_id == transaction.destination_account_id:
            raise InvalidTransactionError("Cannot transfer to the same account.")

        source = self._validate_account_active(transaction.source_account_id)
        destination = self._validate_account_active(transaction.destination_account_id)

        if source.balance < transaction.amount:
            raise InsufficientFundsError(
                f"Insufficient funds in account {source.account_id}. "
                f"Balance: {source.balance}, Requested: {transaction.amount}"
            )

        source.balance -= transaction.amount
        source.balance = round(source.balance, 2)
        destination.balance += transaction.amount
        destination.balance = round(destination.balance, 2)

        source.transaction_history.append(transaction.transaction_id)
        destination.transaction_history.append(transaction.transaction_id)

    def reverse_transaction(self, transaction_id: str) -> Transaction:
        """Reverse a completed transaction."""
        if transaction_id not in self.transactions:
            raise InvalidTransactionError(f"Transaction {transaction_id} not found.")

        original = self.transactions[transaction_id]

        if original.status != TransactionStatus.COMPLETED:
            raise InvalidTransactionError(
                f"Only completed transactions can be reversed. Current status: {original.status.value}"
            )

        # Create a reversal transaction
        reversal = Transaction(
            transaction_id=str(uuid.uuid4())[:8],
            transaction_type=original.transaction_type,
            amount=original.amount,
            source_account_id=original.destination_account_id,
            destination_account_id=original.source_account_id,
            timestamp=datetime.now(),
            description=f"Reversal of transaction {transaction_id}"
        )

        if original.transaction_type == TransactionType.DEPOSIT:
            # Reverse deposit = withdrawal from destination
            reversal.transaction_type = TransactionType.WITHDRAWAL
            reversal.source_account_id = original.destination_account_id
            reversal.destination_account_id = None

        elif original.transaction_type == TransactionType.WITHDRAWAL:
            # Reverse withdrawal = deposit to source
            reversal.transaction_type = TransactionType.DEPOSIT
            reversal.destination_account_id = original.source_account_id
            reversal.source_account_id = None

        # For transfer, source and destination are already swapped above

        self.process_transaction(reversal)

        if reversal.status == TransactionStatus.COMPLETED:
            original.status = TransactionStatus.REVERSED

        return reversal

    def get_account_statement(self, account_id: str) -> dict:
        """Get a summary of the account and its transactions."""
        account = self.get_account(account_id)
        transactions = []
        for tid in account.transaction_history:
            if tid in self.transactions:
                t = self.transactions[tid]
                transactions.append({
                    "transaction_id": t.transaction_id,
                    "type": t.transaction_type.value,
                    "amount": t.amount,
                    "status": t.status.value,
                    "timestamp": t.timestamp.isoformat(),
                    "description": t.description
                })

        return {
            "account_id": account.account_id,
            "owner_name": account.owner_name,
            "current_balance": account.balance,
            "is_active": account.is_active,
            "total_transactions": len(transactions),
            "transactions": transactions
        }

    def get_total_balances(self) -> dict:
        """Get total balances across all accounts."""
        total = sum(acc.balance for acc in self.accounts.values())
        return {
            "total_accounts": len(self.accounts),
            "total_balance": round(total, 2),
            "accounts": {
                acc_id: {"owner": acc.owner_name, "balance": acc.balance}
                for acc_id, acc in self.accounts.items()
            }
        }


def create_transaction(
    transaction_type: TransactionType,
    amount: float,
    source_account_id: Optional[str] = None,
    destination_account_id: Optional[str] = None,
    description: str = ""
) -> Transaction:
    """Helper function to create a Transaction object."""
    return Transaction(
        transaction_id=str(uuid.uuid4())[:8],
        transaction_type=transaction_type,
        amount=amount,
        source_account_id=source_account_id,
        destination_account_id=destination_account_id,
        timestamp=datetime.now(),
        description=description
    )


